export default function FeaturePanel({code, description, title}: Props) {
  return (
    <div className="-mx-4 flex flex-col overflow-hidden border-slate-200 lg:mx-0">
      {code && (
        <div className="grow rounded-sm bg-white dark:bg-slate-800">
          <pre className="-ml-4 overflow-x-auto !p-4 lg:!p-6">{code}</pre>
        </div>
      )}
      <div className="p-4 lg:p-6">
        <h3 className="font-semibold text-slate-900 dark:text-white">
          {title}
        </h3>
        <p className="mt-2 max-w-md text-slate-600 dark:text-slate-400">
          {description}
        </p>
      </div>
    </div>
  );
}

export default function Section({children, description, title}: Props) {
  return (
    <section className="py-20 lg:py-40">
      <Wrapper>
        <div>
          <h2 className="text-2xl font-bold tracking-tight text-slate-900 dark:text-white lg:text-4xl">
            {title}
          </h2>
          <div className="mt-6 max-w-[42rem] text-base text-slate-600 dark:text-slate-400 lg:text-lg">
            {description}
          </div>
        </div>
        <div className="mt-10 lg:mt-24">{children}</div>
      </Wrapper>
    </section>
  );
}

function NavSkeleton({ groups }: { groups: number[][] }) {
  return (
    <div className="flex flex-col gap-1 p-2">
      {groups.map((items, gi) => (
        <div key={gi} className="flex flex-col gap-1 px-2 py-1.5">
          <Skeleton className="mb-1 h-3 w-20 rounded-md" />
          {items.map((item) => (
            <div key={item} className="flex items-center gap-2 px-2 py-2">
              <Skeleton className="size-4 rounded-md" />
              <Skeleton className="h-3 w-24 rounded-md" />
            </div>
          ))}
          {gi < groups.length - 1 && (
            <Skeleton className="my-1 h-px w-full rounded-none" />
          )}
        </div>
      ))}
    </div>
  )
}

function ScrollAreaVertical() {
  return (
    <Example title="Vertical">
      <ScrollArea className="mx-auto h-72 w-48 rounded-md border style-luma:rounded-2xl style-rhea:rounded-2xl">
        <div className="p-4">
          <h4 className="mb-4 text-sm leading-none font-medium">Tags</h4>
          {tags.map((tag) => (
            <React.Fragment key={tag}>
              <div className="text-sm">{tag}</div>
              <Separator className="my-2" />
            </React.Fragment>
          ))}
        </div>
      </ScrollArea>
    </Example>
  )
}

export function BlockViewerFileTree() {
  const { tree } = useBlockViewer()

  if (!tree) {
    return null
  }

  return (
    <SidebarProvider className="flex min-h-full! flex-col border-r">
      <Sidebar collapsible="none" className="w-full flex-1">
        <SidebarGroupLabel className="h-12 rounded-none border-b px-4 text-sm">
          Files
        </SidebarGroupLabel>
        <SidebarGroup className="p-0">
          <SidebarGroupContent>
            <SidebarMenu className="translate-x-0 gap-1.5">
              {tree.map((file, index) => (
                <Tree key={index} item={file} index={1} />
              ))}
            </SidebarMenu>
          </SidebarGroupContent>
        </SidebarGroup>
      </Sidebar>
    </SidebarProvider>
  )
}

export function ColorPalette({ colorPalette }: { colorPalette: ColorPalette }) {
  return (
    <div id={colorPalette.name} className="scroll-mt-20 rounded-lg">
      <div className="flex items-center px-4">
        <div className="flex-1 pl-1 text-sm font-medium">
          <h2 className="capitalize">{colorPalette.name}</h2>
        </div>
        <ColorFormatSelector
          color={colorPalette.colors[0]}
          className="ml-auto"
        />
      </div>
      <div className="flex flex-col gap-4 py-4 sm:flex-row sm:gap-2">
        {colorPalette.colors.map((color) => (
          <Color key={color.hex} color={color} />
        ))}
      </div>
    </div>
  )
}

export function CarouselMultiple() {
  return (
    <Carousel
      className="mx-auto max-w-xs sm:max-w-sm"
      opts={{
        align: "start",
      }}
    >
      <CarouselContent>
        {Array.from({ length: 5 }).map((_, index) => (
          <CarouselItem key={index} className="sm:basis-1/2 lg:basis-1/3">
            <div className="p-1">
              <Card>
                <CardContent className="flex aspect-square items-center justify-center p-6">
                  <span className="text-3xl font-semibold">{index + 1}</span>
                </CardContent>
              </Card>
            </div>
          </CarouselItem>
        ))}
      </CarouselContent>
      <CarouselPrevious className="hidden sm:inline-flex" />
      <CarouselNext className="hidden sm:inline-flex" />
    </Carousel>
  )
}

export default function CarouselOrientation() {
  return (
    <Carousel
      opts={{
        align: "start",
      }}
      orientation="vertical"
      className="w-full max-w-xs"
    >
      <CarouselContent className="-mt-1 h-[270px]">
        {Array.from({ length: 5 }).map((_, index) => (
          <CarouselItem key={index} className="basis-1/2 pt-1">
            <div className="p-1">
              <Card>
                <CardContent className="flex items-center justify-center p-6">
                  <span className="text-3xl font-semibold">{index + 1}</span>
                </CardContent>
              </Card>
            </div>
          </CarouselItem>
        ))}
      </CarouselContent>
      <CarouselPrevious />
      <CarouselNext />
    </Carousel>
  )
}

export default function CarouselSize() {
  return (
    <Carousel
      opts={{
        align: "start",
      }}
      className="w-full max-w-[12rem] sm:max-w-xs md:max-w-sm"
    >
      <CarouselContent>
        {Array.from({ length: 5 }).map((_, index) => (
          <CarouselItem key={index} className="basis-1/2 lg:basis-1/3">
            <div className="p-1">
              <Card>
                <CardContent className="flex aspect-square items-center justify-center p-6">
                  <span className="text-3xl font-semibold">{index + 1}</span>
                </CardContent>
              </Card>
            </div>
          </CarouselItem>
        ))}
      </CarouselContent>
      <CarouselPrevious />
      <CarouselNext />
    </Carousel>
  )
}

function PostItem(props: { post: PostByIdOutput }) {
  const { post } = props;
  return (
    <div className="flex flex-col justify-center h-full px-8 ">
      <Link className="text-gray-300 underline mb-4" href="/">
        Home
      </Link>
      <h1 className="text-4xl font-bold">{post.title}</h1>
      <em className="text-gray-400">
        Created {post.createdAt.toLocaleDateString('en-us')}
      </em>

      <p className="py-4 break-all">{post.text}</p>

      <h2 className="text-2xl font-semibold py-2">Raw data:</h2>
      <pre className="bg-gray-900 p-4 rounded-xl overflow-x-scroll">
        {JSON.stringify(post, null, 4)}
      </pre>
    </div>
  );
}

() => {
  return (
    <div className="mx-auto grid grid-cols-1 gap-6 lg:grid-cols-3">
      {features.map((feature) => {
        return (
          <div key={feature.title}>
            <h2
              className={`${feature.color} mb-3 grid h-12 w-12 place-items-center rounded-xl`}
            >
              {feature.icon}
            </h2>
            <h3 className="text-lg font-bold md:text-xl">{feature.title}</h3>
            <p className="text-sm text-zinc-600 dark:text-zinc-300 md:text-base">
              {feature.description}
            </p>
          </div>
        );
      })}
    </div>
  );
}
